-- 042_seed_honeybook_templates.sql
-- Seeds 13 email templates + 4 questionnaire forms (proofread/adapted
-- from the HoneyBook library). Idempotent: every INSERT is guarded with
-- WHERE NOT EXISTS, so re-running is a no-op. Generated by gen_seed.py.

-- ── Email templates ──────────────────────────────────────────────
INSERT INTO email_templates (name, subject, body)
SELECT 'Booking confirmation + next steps', 'You''re booked! Here''s what happens next', 'Hi {client_name},

I''m looking forward to working together. Now that your [service name] is booked, here''s what happens next:

Before our session, please take a moment to fill out this short intake form: [intake form link]. It gives me helpful insight into your business and what you''re looking for.

If any questions come up before we shoot, just reply here — I''m happy to help.

Thank you!
{site_name}'
WHERE NOT EXISTS (SELECT 1 FROM email_templates WHERE name='Booking confirmation + next steps' AND deleted_at IS NULL);
INSERT INTO email_templates (name, subject, body)
SELECT 'Reply: request for lower price', 'Re: Pricing', 'Hi {first_name},

Thanks so much for your interest in working together. My pricing reflects the time, quality, and care that go into every project, and at this point I''m not able to offer discounts on my rates.

I''d still love to find a way to work together. If the budget doesn''t quite line up, let me know — I''m happy to recommend another photographer who may be a better fit for your needs.

Best,
{site_name}'
WHERE NOT EXISTS (SELECT 1 FROM email_templates WHERE name='Reply: request for lower price' AND deleted_at IS NULL);
INSERT INTO email_templates (name, subject, body)
SELECT 'Client satisfaction survey', 'How did we do?', 'Hi {first_name},

I really enjoyed working with you, and I wanted to follow up to make sure your experience was a great one from start to finish.

Your feedback helps me see what''s working and where I can improve. If you have a few minutes, would you mind sharing your thoughts? It only takes a moment: [feedback survey link]

Thanks so much for your time.

Best,
{site_name}'
WHERE NOT EXISTS (SELECT 1 FROM email_templates WHERE name='Client satisfaction survey' AND deleted_at IS NULL);
INSERT INTO email_templates (name, subject, body)
SELECT 'Reply to inquiry — with brochure', 'Thank you for your inquiry!', 'Hi {first_name},

Thank you for reaching out! I''d love to learn more about your project, and I''m excited about the possibility of working together.

I''ve attached my brochure so you can get a feel for my services and pricing. If you don''t see exactly what you''re looking for, no problem — I''m happy to tailor something to your needs.

When you have a moment, take a look and let me know which services you''d like to explore: [brochure / services link]. Once you''ve made a selection, I''ll reach out to get things started.

In the meantime, please don''t hesitate to send over any questions.

Best,
{site_name}'
WHERE NOT EXISTS (SELECT 1 FROM email_templates WHERE name='Reply to inquiry — with brochure' AND deleted_at IS NULL);
INSERT INTO email_templates (name, subject, body)
SELECT 'Reply: request for a discount (warm)', 'Re: Pricing', 'Hi {first_name},

Thank you so much for your interest — I''m grateful our paths have crossed, and genuinely excited about what you''re planning!

Talking about budget can be a tricky conversation to navigate, and I completely understand. At this point my business has grown to where I''m not able to offer discounted pricing. I''ve adjusted my rates over the years to keep up with demand while making sure every client gets a custom, high-quality experience worth every penny.

I would absolutely love the chance to work with you. If the budget doesn''t allow for it right now, I''m more than happy to point you toward another professional who might be a great fit — just say the word and I''ll share a few recommendations.

Thank you again,
{site_name}'
WHERE NOT EXISTS (SELECT 1 FROM email_templates WHERE name='Reply: request for a discount (warm)' AND deleted_at IS NULL);
INSERT INTO email_templates (name, subject, body)
SELECT 'Gallery delivery — sharing & credit', 'Your gallery is ready!', 'Hi {first_name},

I''m so excited to share that your gallery is ready to view and download! It was a joy hand-picking, fine-tuning, and editing each image, and I hope you love them as much as I do: [gallery link]

I love it when clients share their photos — it''s a wonderful way to let others in on what we created together. You''re more than welcome to post the images anywhere you like. I only ask one small favor: please credit my work, and avoid adding filters or extra edits on top of the photos.

Referrals and tags are one of my main sources of new work, so a quick credit genuinely means the world. To credit me, just tag [your Instagram handle] or mention {site_name} in your caption. It seems like a small thing, but it makes a big difference!

If you have any questions at all, let me know. I can''t wait to see how you use them!

You''re the best,
{site_name}'
WHERE NOT EXISTS (SELECT 1 FROM email_templates WHERE name='Gallery delivery — sharing & credit' AND deleted_at IS NULL);
INSERT INTO email_templates (name, subject, body)
SELECT 'Request for a testimonial', 'A quick favor?', 'Hi {first_name},

Can you believe it''s already been a month since we worked together? Time is flying! I''ve been thinking back to [personal detail from the project].

I wanted to check in, see how you''re doing, and ask whether there''s anything else I can help you with. I''d also love to hear about your experience working with me — what you enjoyed most, and anything I could do better.

If you''re comfortable, would you be willing to spend five minutes sharing a few thoughts? [review link] Reviews are one of the best ways for me to keep every client leaving as a raving fan, and your feedback would mean a lot.

Thank you again for choosing me!

Best,
{site_name}'
WHERE NOT EXISTS (SELECT 1 FROM email_templates WHERE name='Request for a testimonial' AND deleted_at IS NULL);
INSERT INTO email_templates (name, subject, body)
SELECT 'Follow-up: questionnaire (3-day)', 'Just checking in', 'Hi {first_name},

I hope this finds you well!

I wanted to follow up on the questionnaire I sent over to get things started. You can fill it out here whenever you have a moment: [questionnaire link]

I''d love to find a time to talk through the details soon. Are you free this week? Once you''ve submitted the questionnaire, you can grab a slot that works for you here: [scheduling link]

Looking forward to it!
{site_name}'
WHERE NOT EXISTS (SELECT 1 FROM email_templates WHERE name='Follow-up: questionnaire (3-day)' AND deleted_at IS NULL);
