SELECT 'GZGCNSuABjKiMr', 'Experience Questionnaire', 'questionnaire', 'It''s been such a pleasure working together. Please take a moment to let me know how the experience felt for you. I welcome constructive criticism as much as positive feedback.', 1
WHERE NOT EXISTS (SELECT 1 FROM forms WHERE title='Experience Questionnaire');
INSERT INTO form_fields (form_id, label, ftype, required, options, sort_order)
SELECT f.id, 'What was the primary service we worked on together?', 'short_text', 1, NULL, 1
FROM forms f WHERE f.slug='GZGCNSuABjKiMr'
  AND NOT EXISTS (SELECT 1 FROM form_fields ff WHERE ff.form_id=f.id AND ff.label='What was the primary service we worked on together?');
INSERT INTO form_fields (form_id, label, ftype, required, options, sort_order)
SELECT f.id, 'How satisfied are you with your overall experience?', 'dropdown', 0, '["Extremely satisfied", "Satisfied", "Neutral", "Unsatisfied"]', 2
FROM forms f WHERE f.slug='GZGCNSuABjKiMr'
  AND NOT EXISTS (SELECT 1 FROM form_fields ff WHERE ff.form_id=f.id AND ff.label='How satisfied are you with your overall experience?');
